import type { FrameNode } from '../../operation-node/frame-node.js'
import type { OverNode } from '../../operation-node/over-node.js'
import { OperationNodeTransformer } from '../../operation-node/operation-node-transformer.js'
import { freeze } from '../../util/object-utils.js'
import type { QueryId } from '../../util/query-id.js'

export class SimplifyFrameTransformer extends OperationNodeTransformer {
  protected override transformOver(
    node: OverNode,
    queryId: QueryId,
  ): OverNode {
    const transformed = super.transformOver(node, queryId)

    if (
      transformed.frame &&
      isRedundantFrame(transformed.frame, !!transformed.orderBy)
    ) {
      return freeze({
        ...transformed,
        frame: undefined,
      })
    }

    return transformed
  }
}

function isRedundantFrame(frame: FrameNode, hasOrderBy: boolean): boolean {
  if (frame.type !== 'range' || frame.exclusion || !frame.end) {
    return false
  }

  const [expectedStart, expectedEnd]: [FrameBoundNode['type'], FrameBoundNode['type']] =
    hasOrderBy
      ? ['unbounded preceding', 'current row']
      : ['unbounded preceding', 'unbounded following']

  return (
    isPlainBound(frame.start, expectedStart) &&
    isPlainBound(frame.end, expectedEnd)
  )
}

function isPlainBound(
  bound: FrameBoundNode,
  type: FrameBoundNode['type'],
): boolean {
  return bound.type === type && bound.offset === undefined
}
