/**
 * Plugin that strips `over` clause frame extents that are redundant because
 * they simply replicate the SQL-standard implicit default.
 *
 * When an `over` clause has an `order by`, the database implicitly applies
 * `range between unbounded preceding and current row`. When it has no
 * `order by`, the implicit default is
 * `range between unbounded preceding and unbounded following`.
 *
 * Any frame using `rows`/`groups` mode, carrying an exclusion clause, or
 * using non-default bound types or expression-based offsets is left
 * untouched.
 */
export class SimplifyFramePlugin implements KyselyPlugin {
  readonly #transformer = new SimplifyFrameTransformer()

  transformQuery(args: PluginTransformQueryArgs): RootOperationNode {
    return this.#transformer.transformNode(args.node, args.queryId)
  }

  transformResult(
    args: PluginTransformResultArgs,
  ): Promise<QueryResult<UnknownRow>> {
    return Promise.resolve(args.result)
  }
}
